package com.example.oidc.config;

import com.example.oidc.security.OidcAuthenticationSuccessHandler;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.core.authority.mapping.SimpleAuthorityMapper;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.oauth2.client.registration.InMemoryClientRegistrationRepository;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.AuthorizationGrantType;
import org.springframework.security.oauth2.core.ClientAuthenticationMethod;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
public class SecurityConfig {

    @Value("${app.oidc.client-id}")
    private String clientId;

    @Value("${app.oidc.client-secret}")
    private String clientSecret;

    @Value("${app.oidc.redirect-uri}")
    private String redirectUri;

    @Value("${app.oidc.scope}")
    private String scope;

    @Value("${app.oidc.authorization-uri}")
    private String authorizationUri;

    @Value("${app.oidc.token-uri}")
    private String tokenUri;

    @Value("${app.oidc.user-info-uri}")
    private String userInfoUri;

    @Value("${app.oidc.jwk-set-uri}")
    private String jwkSetUri;

    @Value("${app.oidc.issuer-uri:}")
    private String issuerUri;

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http,
                                                   OidcAuthenticationSuccessHandler successHandler) throws Exception {
        http
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/", "/error").permitAll()
                .anyRequest().authenticated()
            )
            .oauth2Login(oauth2 -> oauth2
                .successHandler(successHandler)
                .userInfoEndpoint(userInfo -> userInfo
                    .oidcUserService(oidcUserService())
                )
            )
            .logout(logout -> logout
                .logoutSuccessUrl("/")
            )
            .oauth2Client(Customizer.withDefaults());

        return http.build();
    }

    @Bean
    public ClientRegistrationRepository clientRegistrationRepository() {
        ClientRegistration.Builder builder = ClientRegistration.withRegistrationId("custom-oidc")
            .clientId(clientId)
            .clientSecret(clientSecret)
            .clientAuthenticationMethod(ClientAuthenticationMethod.CLIENT_SECRET_BASIC)
            .authorizationGrantType(AuthorizationGrantType.AUTHORIZATION_CODE)
            .redirectUri(redirectUri)
            .scope(scope.split(","))
            .authorizationUri(authorizationUri)
            .tokenUri(tokenUri)
            .userInfoUri(userInfoUri)
            .userNameAttributeName("sub")
            .jwkSetUri(jwkSetUri)
            .clientName("Custom OIDC");

        if (issuerUri != null && !issuerUri.isBlank()) {
            builder.issuerUri(issuerUri);
        }

        return new InMemoryClientRegistrationRepository(builder.build());
    }

    @Bean
    public OidcUserService oidcUserService() {
        OidcUserService service = new OidcUserService();
        SimpleAuthorityMapper authorityMapper = new SimpleAuthorityMapper();
        authorityMapper.setConvertToUpperCase(true);
        authorityMapper.setDefaultAuthority("ROLE_USER");
        return service;
    }
}

package com.example.oidc.security;

import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.client.authentication.OAuth2AuthenticationToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@Component
public class OidcAuthenticationSuccessHandler implements AuthenticationSuccessHandler {

    @Override
    public void onAuthenticationSuccess(HttpServletRequest request,
                                        HttpServletResponse response,
                                        Authentication authentication) throws IOException, ServletException {
        HttpSession session = request.getSession(true);

        if (authentication instanceof OAuth2AuthenticationToken oauthToken
            && oauthToken.getPrincipal() instanceof OidcUser oidcUser) {

            Map<String, Object> userSession = new HashMap<>();
            userSession.put("subject", oidcUser.getSubject());
            userSession.put("fullName", oidcUser.getFullName());
            userSession.put("email", oidcUser.getEmail());
            userSession.put("preferredUsername", oidcUser.getPreferredUsername());
            userSession.put("issuer", oidcUser.getIssuer() != null ? oidcUser.getIssuer().toString() : null);
            userSession.put("audience", oidcUser.getAudience());
            userSession.put("issuedAt", oidcUser.getIssuedAt());
            userSession.put("expiresAt", oidcUser.getExpiresAt());
            userSession.put("claims", oidcUser.getClaims());

            session.setAttribute("OIDC_USER", userSession);
        }

        response.sendRedirect("/profile");
    }
}

package com.example.oidc.web;

import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.client.OAuth2AuthorizedClient;
import org.springframework.security.oauth2.client.annotation.RegisteredOAuth2AuthorizedClient;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class HomeController {

    @GetMapping("/")
    public Map<String, Object> home(Authentication authentication) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("message", "OIDC client application");
        response.put("authenticated", authentication != null && authentication.isAuthenticated());
        response.put("login", "/oauth2/authorization/custom-oidc");
        return response;
    }

    @GetMapping("/profile")
    public Map<String, Object> profile(Authentication authentication,
                                       HttpSession session,
                                       @RegisteredOAuth2AuthorizedClient("custom-oidc") OAuth2AuthorizedClient authorizedClient) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("authenticated", authentication != null && authentication.isAuthenticated());
        response.put("sessionUser", session.getAttribute("OIDC_USER"));

        if (authentication != null && authentication.getPrincipal() instanceof OidcUser oidcUser) {
            response.put("idTokenClaims", oidcUser.getIdToken().getClaims());
            response.put("userInfoClaims", oidcUser.getUserInfo() != null ? oidcUser.getUserInfo().getClaims() : Map.of());
        }

        if (authorizedClient != null) {
            Map<String, Object> tokens = new LinkedHashMap<>();
            tokens.put("accessToken", authorizedClient.getAccessToken().getTokenValue());
            tokens.put("accessTokenIssuedAt", authorizedClient.getAccessToken().getIssuedAt());
            tokens.put("accessTokenExpiresAt", authorizedClient.getAccessToken().getExpiresAt());
            tokens.put("scopes", authorizedClient.getAccessToken().getScopes());
            if (authorizedClient.getRefreshToken() != null) {
                tokens.put("refreshToken", authorizedClient.getRefreshToken().getTokenValue());
            }
            response.put("tokens", tokens);
        }

        return response;
    }
}

